concept_explanation.two_level_cache:
**Two-level cache implementation:**

```java
@Service
public class ProductCacheService {
    private final Cache<String, Product> l1;  // Caffeine: fast, in-process
    private final RedisTemplate<String, Product> redis;  // L2: shared across instances
    private final ProductRepository repo;  // DB fallback
    private final Counter l1Hits, l2Hits, dbHits;

    ProductCacheService(MeterRegistry reg, RedisTemplate<String, Product> redis,
                        ProductRepository repo) {
        this.l1 = Caffeine.newBuilder()
            .maximumSize(1000)          // in-process: keep memory bounded
            .expireAfterWrite(30, TimeUnit.SECONDS)  // short TTL: L1 is a buffer
            .recordStats()              // track hit/miss stats
            .build();
        this.redis = redis;
        this.repo = repo;
        l1Hits = reg.counter("cache.hits", "level", "l1");
        l2Hits = reg.counter("cache.hits", "level", "l2");
        dbHits = reg.counter("cache.hits", "level", "db");
    }

    public Product getProduct(String id) {
        // L1: check Caffeine first (microseconds)
        Product p = l1.getIfPresent(id);
        if (p != null) { l1Hits.increment(); return p; }

        // L2: check Redis (1ms)
        p = redis.opsForValue().get("product:" + id);
        if (p != null) {
            l2Hits.increment();
            l1.put(id, p);  // populate L1 from L2
            return p;
        }

        // DB fallback (5ms)
        p = repo.findById(id).orElseThrow();
        dbHits.increment();
        redis.opsForValue().set("product:" + id, p, 5, TimeUnit.MINUTES);
        l1.put(id, p);
        return p;
    }
}
```
